INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Upward_Stretch','Upward Stretch','hombros',ARRAY['pecho','dorsales'],NULL,'stretching',ARRAY['Extend both hands straight above your head, palms touching.','Slowly push your hands up and back, keeping your back straight.'],'Extend both hands straight above your head, palms touching. Slowly push your hands up and back, keeping your back straight.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Upward_Stretch/0.jpg','exercisedb',true),('V-Bar_Pulldown','V-Bar Pulldown','dorsales',ARRAY['bíceps','espalda media','hombros'],'cable','strength',ARRAY['Sit down on a pull-down machine with a V-Bar attached to the top pulley.','Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.','Grab the V-bar with the palms facing each other (a neutral grip). Stick your chest out and lean yourself back slightly (around 30-degrees) in order to better engage the lats. This will be your starting position.','Using your lats, pull the bar down as you squeeze your shoulder blades. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion. Tip: Keep the torso stationary throughout the movement.','After a second hold on the contracted position, slowly bring the bar back to the starting position as you breathe in.','Repeat for the prescribed number of repetitions.'],'Sit down on a pull-down machine with a V-Bar attached to the top pulley. Adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar. Grab the V-bar with the palms facing each other (a neutral grip). Stick your chest out and lean yourself back slightly (around 30-degrees) in order to better engage the lats. This will be your starting position. Using your lats, pull the bar down as you squeeze your shoulder blades. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion. Tip: Keep the torso stationary throughout the movement. After a second hold on the contracted position, slowly bring the bar back to the starting position as you breathe in. Repeat for the prescribed number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/V-Bar_Pulldown/0.jpg','exercisedb',true),('V-Bar_Pullup','V-Bar Pullup','dorsales',ARRAY['bíceps','espalda media','hombros'],'peso corporal','strength',ARRAY['Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles.','Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position.','Using your lats, pull your torso up while leaning your head back slightly so that you do not hit yourself with the chin-up bar. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion.','After a second hold on the contracted position, slowly lower your body back to the starting position as you breathe in.','Repeat for the prescribed number of repetitions.'],'Start by placing the middle of the V-bar in the middle of the pull-up bar (assuming that the pull-up station you are using does not have neutral grip handles). The V-Bar handles will be facing down so that you can hang from the pull-up bar through the use of the handles. Once you securely place the V-bar, take a hold of the bar from each side and hang from it. Stick your chest out and lean yourself back slightly in order to better engage the lats. This will be your starting position. Using your lats, pull your torso up while leaning your head back slightly so that you do not hit yourself with the chin-up bar. Continue until your chest nearly touches the V-bar. Exhale as you execute this motion. After a second hold on the contracted position, slowly lower your body back to the starting position as you breathe in. Repeat for the prescribed number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/V-Bar_Pullup/0.jpg','exercisedb',true),('Vertical_Swing','Vertical Swing','isquiotibiales',ARRAY['glúteos','cuádriceps','hombros'],'mancuernas','plyometrics',ARRAY['Allow the dumbbell to hang at arms length between your legs, holding it with both hands. Keep your back straight and your head up.','Swing the dumbbell between your legs, flexing at the hips and bending the knees slightly.','Powerfully reverse the motion by extending at the hips, knees, and ankles to propel yourself upward, swinging the dumbell over your head.','As you land, absorb the impact through your legs and draw the dumbbell to your torso before the next repetition.'],'Allow the dumbbell to hang at arms length between your legs, holding it with both hands. Keep your back straight and your head up. Swing the dumbbell between your legs, flexing at the hips and bending the knees slightly. Powerfully reverse the motion by extending at the hips, knees, and ankles to propel yourself upward, swinging the dumbell over your head. As you land, absorb the impact through your legs and draw the dumbbell to your torso before the next repetition.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Vertical_Swing/0.jpg','exercisedb',true),('Walking_Treadmill','Walking, Treadmill','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','cardio',ARRAY['To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','Treadmills offer convenience, cardiovascular benefits, and usually have less impact than walking outside. When walking, you should move at a moderate to fast pace, not a leisurely one. Being an activity of lower intensity, walking doesn''''t burn as many calories as some other activities, but still provides great benefit. A 150 lb person will burn about 175 calories walking 4 miles per hour for 30 minutes, compared to 450 calories running twice as fast. Maintain proper posture as you walk, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.'],'To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout. Treadmills offer convenience, cardiovascular benefits, and usually have less impact than walking outside. When walking, you should move at a moderate to fast pace, not a leisurely one. Being an activity of lower intensity, walking doesn''t burn as many calories as some other activities, but still provides great benefit. A 150 lb person will burn about 175 calories walking 4 miles per hour for 30 minutes, compared to 450 calories running twice as fast. Maintain proper posture as you walk, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Walking_Treadmill/0.jpg','exercisedb',true),('Weighted_Ball_Hyperextension','Weighted Ball Hyperextension','espalda baja',ARRAY['glúteos','isquiotibiales','espalda media'],'pelota de ejercicio','strength',ARRAY['To begin, lie down on an exercise ball with your torso pressing against the ball and parallel to the floor. The ball of your feet should be pressed against the floor to help keep you balanced. Place a weighted plate under your chin or behind your neck. This is the starting position.','Slowly raise your torso up by bending at the waist and lower back. Remember to exhale during this movement.','Hold the contraction on your lower back for a second and lower your torso back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions prescribed in your program.'],'To begin, lie down on an exercise ball with your torso pressing against the ball and parallel to the floor. The ball of your feet should be pressed against the floor to help keep you balanced. Place a weighted plate under your chin or behind your neck. This is the starting position. Slowly raise your torso up by bending at the waist and lower back. Remember to exhale during this movement. Hold the contraction on your lower back for a second and lower your torso back down to the starting position while inhaling. Repeat for the recommended amount of repetitions prescribed in your program.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Ball_Hyperextension/0.jpg','exercisedb',true),('Weighted_Ball_Side_Bend','Weighted Ball Side Bend','abdominales',ARRAY[]::text[],'pelota de ejercicio','strength',ARRAY['To begin, lie down on an exercise ball with your left side of the torso (waist, hips and shoulder) pressed against the ball.','Your feet should be on the floor while your legs are crossed and hanging from the ball. Hold a weighted plate with your right hand directly to the right side of your head. Tip: Make sure the smooth side of the plate is resting against your head.','Place your left arm across your torso so that your palm is on your obliques. There should be a right angle between your left forearm and upper arm. This is the starting position.','Raise the side of your torso up by laterally flexing at the waist while exhaling.','Hold the contraction for a second and slowly lower yourself back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.','Switch sides and repeat the exercise.'],'To begin, lie down on an exercise ball with your left side of the torso (waist, hips and shoulder) pressed against the ball. Your feet should be on the floor while your legs are crossed and hanging from the ball. Hold a weighted plate with your right hand directly to the right side of your head. Tip: Make sure the smooth side of the plate is resting against your head. Place your left arm across your torso so that your palm is on your obliques. There should be a right angle between your left forearm and upper arm. This is the starting position. Raise the side of your torso up by laterally flexing at the waist while exhaling. Hold the contraction for a second and slowly lower yourself back down to the starting position while inhaling. Repeat for the recommended amount of repetitions. Switch sides and repeat the exercise.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Ball_Side_Bend/0.jpg','exercisedb',true),('Weighted_Bench_Dip','Weighted Bench Dip','tríceps',ARRAY['pecho','hombros'],'otro','strength',ARRAY['For this exercise you will need to place a bench behind your back and another one in front of you. With the benches perpendicular to your body, hold on to one bench on its edge with the hands close to your body, separated at shoulder width. Your arms should be fully extended.','The legs will be extended forward on top of the other bench. Your legs should be parallel to the floor while your torso is to be perpendicular to the floor. Have your partner place the dumbbell on your lap. Note: This exercise is best performed with a partner as placing the weight on your lap can be challenging and cause injury without assistance. This will be your starting position.','Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down.','Using your triceps to bring your torso up again, lift yourself back to the starting position while exhaling.','Repeat for the recommended amount of repetitions.'],'For this exercise you will need to place a bench behind your back and another one in front of you. With the benches perpendicular to your body, hold on to one bench on its edge with the hands close to your body, separated at shoulder width. Your arms should be fully extended. The legs will be extended forward on top of the other bench. Your legs should be parallel to the floor while your torso is to be perpendicular to the floor. Have your partner place the dumbbell on your lap. Note: This exercise is best performed with a partner as placing the weight on your lap can be challenging and cause injury without assistance. This will be your starting position. Slowly lower your body as you inhale by bending at the elbows until you lower yourself far enough to where there is an angle slightly smaller than 90 degrees between the upper arm and the forearm. Tip: Keep the elbows as close as possible throughout the movement. Forearms should always be pointing down. Using your triceps to bring your torso up again, lift yourself back to the starting position while exhaling. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Bench_Dip/0.jpg','exercisedb',true),('Weighted_Crunches','Weighted Crunches','abdominales',ARRAY[]::text[],'balón medicinal','strength',ARRAY['Lie flat on your back with your feet flat on the ground or resting on a bench with your knees bent at a 90 degree angle.','Hold a weight to your chest, or you may hold it extended above your torso. This will be your starting position.','Now, exhale and slowly begin to roll your shoulders off the floor. Your shoulders should come up off the floor about 4 inches while your lower back remains on the floor.','At the top of the movement, flex your abdominals and hold for a brief pause.','Then inhale and slowly lower yourself back down to the starting position.'],'Lie flat on your back with your feet flat on the ground or resting on a bench with your knees bent at a 90 degree angle. Hold a weight to your chest, or you may hold it extended above your torso. This will be your starting position. Now, exhale and slowly begin to roll your shoulders off the floor. Your shoulders should come up off the floor about 4 inches while your lower back remains on the floor. At the top of the movement, flex your abdominals and hold for a brief pause. Then inhale and slowly lower yourself back down to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Crunches/0.jpg','exercisedb',true),('Weighted_Jump_Squat','Weighted Jump Squat','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales','espalda baja'],'barra','strength',ARRAY['Position a lightly loaded barbell across the back of your shoulders. You could also use a weighted vest, sandbag, or other type of resistance for this exercise.','The weight should be light enough that it doesn''''t slow you down significantly. Your feet should be just outside of shoulder width with your head and chest up. This will be your starting position.','Using a countermovement, squat partially down and immediately reverse your direction to explode off of the ground, extending through your hips, knees, and ankles. Maintain good posture throughout the jump.','As you return to the ground, absorb the impact through your legs.'],'Position a lightly loaded barbell across the back of your shoulders. You could also use a weighted vest, sandbag, or other type of resistance for this exercise. The weight should be light enough that it doesn''t slow you down significantly. Your feet should be just outside of shoulder width with your head and chest up. This will be your starting position. Using a countermovement, squat partially down and immediately reverse your direction to explode off of the ground, extending through your hips, knees, and ankles. Maintain good posture throughout the jump. As you return to the ground, absorb the impact through your legs.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Weighted_Jump_Squat/0.jpg','exercisedb',true);